const recipientId = $('Messenger').first().json.body.entry[0].messaging[0].sender.id
// Text cần gửi (có thể lấy từ AI hoặc node trước)
let text = $input.first().json.output.trim();
const limit = 2000;

let parts = [];
while (text.length > limit) {
    // Ưu tiên cắt tại dấu xuống hàng trước limit
    let cutIndex = text.lastIndexOf('\n', limit);

    // Nếu không có dấu xuống hàng, fallback sang khoảng trắng
    if (cutIndex === -1) cutIndex = text.lastIndexOf(' ', limit);

    // Nếu vẫn không có, cắt cứng theo limit
    if (cutIndex === -1) cutIndex = limit;

    parts.push(text.slice(0, cutIndex).trim());
    text = text.slice(cutIndex).trim();
}

if (text.length > 0) parts.push(text);

// Trả ra nhiều item
return parts.map(p => ({
  json: {
    data: {
      recipient: { id: recipientId },
      message: { text: p }
    }
  }
}));

