// n8n Function Node

// 1) Lấy toàn bộ items từ node trước (đã được SQL sort newest -> oldest)
const items = $input.all();

// 2) Trích JSON
const records = items.map(i => i.json);

// 3) Map thành các dòng "ROLE: content"
// - ROLE: "Bot" nếu message.type === 'ai', "User" nếu === 'human', ngược lại "Unknown"
// - Bỏ qua bản ghi không có message.content dạng string
const lines = records.map(r => {
  const type = r?.message?.type;
  const role =
    type === 'ai' ? 'Bot' :
    type === 'human' ? 'User' :
    'Unknown';

  const content = typeof r?.message?.content === 'string'
    ? r.message.content.trim()
    : '';

  if (!content) return null;

  return `${role}: ${content}`;
}).filter(Boolean);

// 4) Ghép thành chuỗi
const message = lines.join('\n');
const data = $('Messenger').all()
// 5) Trả ra 1 item duy nhất
return [
  {
    json: {
      message,
      data
    }
  }
];

